            sentence_parts.append(f"born on {obj}")
        elif predicate == "occupation":
            sentence_parts.append(f"worked as a {obj}")
        elif predicate == "status":
            sentence_parts.append(f"currently {obj}")
        elif predicate == "almaMater":
            sentence_parts.append(f"educated at {obj}")
        elif predicate == "mission":
            sentence_parts.append(f"was on mission {obj}")
        elif predicate == "selectedByNasa":
            sentence_parts.append(f"selected by NASA in {obj}")
        elif predicate == "timeInSpace":
            sentence_parts.append(f"spent {obj} minutes in space")
        elif predicate == "dateOfRetirement":
            sentence_parts.append(f"retired in {obj}")
        elif predicate == "awards":
            sentence_parts.append(f"received {obj} awards")
        elif predicate == "award":
            sentence_parts.append(f"received the {obj}")
        elif predicate == "ribbonAward":
            sentence_parts.append(f"earned the {obj}")
        elif predicate == "title":
            sentence_parts.append(f"held the title of {obj}")
        elif predicate == "servedAsChiefOfTheAstronautOfficeIn":
            sentence_parts.append(f"served as Chief of the Astronaut Office in {obj}")
        elif predicate == "deathDate":
            sentence_parts.append(f"died on {obj}")
        elif predicate == "commander":
            sentence_parts.append(f"commanded by {obj}")
        elif predicate == "crewMembers":
            sentence_parts.append(f"with crew member {obj}")
        elif predicate == "backupPilot":
            sentence_parts.append(f"with backup pilot {obj}")
        elif predicate == "operator":
            sentence_parts.append(f"operated by {obj}")

    # Build the final sentence
    if not sentence_parts:
        return f"{main_subject} is an astronaut."

    if len(sentence_parts) == 1:
        return f"{main_subject} {sentence_parts[0]}."
